        raise ValueError(f'Invalid mode type: {model_type}')
    if len(indexlines) < 2:
        return ''
    elif len(indexlines) > 2:
        # Only Keep the last code block
        indexlines = indexlines[-2:]
    return '\n'.join(outputlines[indexlines[0] + 1:indexlines[1]])
